tool_calls:
awk -F, '
  # Load products: product_id -> category and price
  NR==FNR {
    if (FNR>1) { cat[$1]=$3; price[$1]=$4 }
    next
  }
  # Process orders
  FNR>1 {
    pid=$2; qty=$3
    revenue[cat[pid]] += qty * price[pid]
  }
  END {
    for (c in revenue) print revenue[c]"\t"c
  }
' /data/products.csv /data/orders.csv | sort -rn | awk -F'\t' '{print $2": "$1}'

